/** @generated —
 * Generate model-swap code when a cheaper model works for certain prompts
 * Pure function — no I/O
 */

export interface ModelSwapInput {
  originalModel: string;
  suggestedModel: string;
  qualityScore: number;
  costReductionPercent: number;
  promptCategory: string;
}

/**
 * Generate TypeScript code for model swapping
 */
export function generateModelSwap(input: ModelSwapInput): string {
  const lines = [
    '// Auto-generated by Flusk — model swap optimization',
    `// Swap ${input.originalModel} → ${input.suggestedModel}`,
    `// Quality score: ${input.qualityScore}% | Cost reduction: ${input.costReductionPercent}%`,
    '',
    `import Flusk from '@flusk/sdk';`,
    '',
    'const flusk = new Flusk({ apiKey: process.env.FLUSK_API_KEY! });',
    '',
    `/**`,
    ` * Route "${input.promptCategory}" prompts to cheaper model`,
    ` */`,
    'export async function optimizedCall(prompt: string) {',
    '  const route = await flusk.route({',
    `    prompt,`,
    `    originalModel: '${input.originalModel}',`,
    `  });`,
    '',
    '  // Flusk automatically selects the best model',
    '  return callLLM(route.selectedModel, prompt);',
    '}',
    '',
    '// Direct swap (no Flusk routing):',
    'export function directSwap(prompt: string) {',
    `  return callLLM('${input.suggestedModel}', prompt);`,
    '}',
    '',
    'function callLLM(model: string, prompt: string) {',
    '  // Replace with your LLM client call',
    '  return { model, prompt };',
    '}',
  ];

  return lines.join('\n');
}
